<template>
  <div class="coupon-list-container">
    <el-card>
      <div class="toolbar">
        <el-button type="primary" class="add-btn" icon="el-icon-plus" @click="handleAdd">添加优惠券</el-button>
      </div>

      <el-table v-loading="listLoading" :data="list" border stripe>
        <el-table-column prop="name" label="优惠券名称" min-width="140"></el-table-column>
        <el-table-column label="类型" width="100">
          <template slot-scope="scope">
            <el-tag :type="scope.row.type === 'full_reduction' ? 'primary' : 'success'">
              {{ scope.row.type === 'full_reduction' ? '满减券' : '折扣券' }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column label="面值" width="120">
          <template slot-scope="scope">
            <span v-if="scope.row.type === 'full_reduction'" class="face-value">
              满{{ scope.row.minAmount }}减{{ scope.row.reduceAmount }}
            </span>
            <span v-else class="face-value">
              {{ scope.row.discountRate }}折
            </span>
          </template>
        </el-table-column>
        <el-table-column label="使用门槛" width="110">
          <template slot-scope="scope">
            <span v-if="scope.row.type === 'full_reduction'">
              ¥{{ scope.row.minAmount }}
            </span>
            <span v-else>¥{{ scope.row.thresholdAmount || 0 }}</span>
          </template>
        </el-table-column>
        <el-table-column label="有效期" width="210">
          <template slot-scope="scope">
            <span>{{ scope.row.startTime }} ~ {{ scope.row.endTime }}</span>
          </template>
        </el-table-column>
        <el-table-column label="发放量/使用量" width="140">
          <template slot-scope="scope">
            <span>{{ scope.row.totalCount }} / {{ scope.row.usedCount }}</span>
          </template>
        </el-table-column>
        <el-table-column label="状态" width="90">
          <template slot-scope="scope">
            <el-switch
              v-model="scope.row.enabled"
              active-color="#9c6e21"
              @change="handleStatusChange(scope.row)"
            ></el-switch>
          </template>
        </el-table-column>
        <el-table-column label="操作" width="150" fixed="right">
          <template slot-scope="scope">
            <el-button size="mini" type="text" class="action-btn" @click="handleEdit(scope.row)">编辑</el-button>
            <el-button size="mini" type="text" class="action-btn danger" @click="handleDelete(scope.row)">删除</el-button>
          </template>
        </el-table-column>
      </el-table>

      <el-empty v-if="!listLoading && list.length === 0" description="暂无数据" />

      <div class="pagination-wrapper">
        <el-pagination
          background
          @size-change="handleSizeChange"
          @current-change="handleCurrentChange"
          :current-page="page"
          :page-sizes="[10, 20, 30, 50]"
          :page-size="pageSize"
          layout="total, sizes, prev, pager, next, jumper"
          :total="total"
        ></el-pagination>
      </div>
    </el-card>

    <!-- 添加/编辑弹窗 -->
    <el-dialog
      :title="dialogMode === 'create' ? '添加优惠券' : '编辑优惠券'"
      :visible.sync="dialogVisible"
      width="580px"
      :close-on-click-modal="false"
    >
      <el-form ref="couponForm" :model="form" :rules="rules" label-width="100px">
        <el-form-item label="优惠券名称" prop="name">
          <el-input v-model="form.name" placeholder="请输入优惠券名称" maxlength="30" show-word-limit></el-input>
        </el-form-item>
        <el-form-item label="优惠券类型" prop="type">
          <el-radio-group v-model="form.type" @change="handleTypeChange">
            <el-radio label="full_reduction">满减券</el-radio>
            <el-radio label="discount">折扣券</el-radio>
          </el-radio-group>
        </el-form-item>
        <template v-if="form.type === 'full_reduction'">
          <el-form-item label="满减门槛" prop="minAmount">
            <el-input-number v-model="form.minAmount" :precision="2" :min="0.01" :step="10" style="width:180px"></el-input-number>
            <span class="unit">元</span>
          </el-form-item>
          <el-form-item label="减免金额" prop="reduceAmount">
            <el-input-number v-model="form.reduceAmount" :precision="2" :min="0.01" :step="5" style="width:180px"></el-input-number>
            <span class="unit">元</span>
          </el-form-item>
        </template>
        <template v-if="form.type === 'discount'">
          <el-form-item label="使用门槛" prop="thresholdAmount">
            <el-input-number v-model="form.thresholdAmount" :precision="2" :min="0" :step="10" style="width:180px"></el-input-number>
            <span class="unit">元（0表示无门槛）</span>
          </el-form-item>
          <el-form-item label="折扣" prop="discountRate">
            <el-input-number v-model="form.discountRate" :precision="1" :min="0.1" :max="9.9" :step="0.5" style="width:180px"></el-input-number>
            <span class="unit">折（如8.5折）</span>
          </el-form-item>
        </template>
        <el-form-item label="有效期" prop="dateRange">
          <el-date-picker
            v-model="form.dateRange"
            type="daterange"
            range-separator="至"
            start-placeholder="开始日期"
            end-placeholder="结束日期"
            value-format="yyyy-MM-dd"
            style="width:100%"
          ></el-date-picker>
        </el-form-item>
        <el-form-item label="发放总量" prop="totalCount">
          <el-input-number v-model="form.totalCount" :min="1" :max="99999" style="width:180px"></el-input-number>
          <span class="unit">张</span>
        </el-form-item>
        <el-form-item label="是否启用" prop="enabled">
          <el-switch
            v-model="form.enabled"
            active-color="#9c6e21"
            active-text="启用"
            inactive-text="禁用"
          ></el-switch>
        </el-form-item>
      </el-form>
      <div slot="footer" class="dialog-footer">
        <el-button @click="dialogVisible = false">取 消</el-button>
        <el-button type="primary" class="submit-btn" @click="submitForm" :loading="submitLoading">确 定</el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>
import couponApi from '@/api/coupon'

export default {
  name: 'CouponList',
  data() {
    return {
      list: [],
      total: 0,
      page: 1,
      pageSize: 10,
      listLoading: false,
      dialogVisible: false,
      dialogMode: 'create',
      submitLoading: false,
      editingId: null,
      form: {
        name: '',
        type: 'full_reduction',
        minAmount: 100,
        reduceAmount: 10,
        thresholdAmount: 0,
        discountRate: 8.5,
        dateRange: [],
        totalCount: 100,
        enabled: true
      },
      rules: {
        name: [{ required: true, message: '请输入优惠券名称', trigger: 'blur' }],
        type: [{ required: true, message: '请选择优惠券类型', trigger: 'change' }],
        minAmount: [{ required: true, type: 'number', min: 0.01, message: '请设置满减门槛金额', trigger: 'blur' }],
        reduceAmount: [{ required: true, type: 'number', min: 0.01, message: '请设置减免金额', trigger: 'blur' }],
        thresholdAmount: [{ required: true, type: 'number', min: 0, message: '请设置使用门槛', trigger: 'blur' }],
        discountRate: [{ required: true, type: 'number', min: 0.1, max: 9.9, message: '请设置折扣(0.1~9.9)', trigger: 'blur' }],
        dateRange: [{ required: true, type: 'array', min: 2, message: '请选择有效期', trigger: 'change' }],
        totalCount: [{ required: true, type: 'number', min: 1, message: '请设置发放总量', trigger: 'blur' }]
      }
    }
  },
  created() {
    this.fetchList()
  },
  methods: {
    fetchList() {
      this.listLoading = true
      const params = { page: this.page, pageSize: this.pageSize }
      couponApi.getList(params).then(res => {
        if (res.code === 0) {
          this.list = (res.data.list || []).map(item => ({
            ...item,
            enabled: item.status === 1
          }))
          this.total = res.data.total || 0
        }
        this.listLoading = false
      }).catch(() => {
        this.listLoading = false
      })
    },
    handleAdd() {
      this.dialogMode = 'create'
      this.editingId = null
      this.form = {
        name: '',
        type: 'full_reduction',
        minAmount: 100,
        reduceAmount: 10,
        thresholdAmount: 0,
        discountRate: 8.5,
        dateRange: [],
        totalCount: 100,
        enabled: true
      }
      this.$nextTick(() => {
        this.$refs.couponForm && this.$refs.couponForm.clearValidate()
      })
      this.dialogVisible = true
    },
    handleEdit(row) {
      this.dialogMode = 'update'
      this.editingId = row.id
      this.form = {
        name: row.name,
        type: row.type,
        minAmount: row.minAmount || 100,
        reduceAmount: row.reduceAmount || 10,
        thresholdAmount: row.thresholdAmount || 0,
        discountRate: row.discountRate || 8.5,
        dateRange: [row.startTime, row.endTime],
        totalCount: row.totalCount,
        enabled: row.enabled !== undefined ? row.enabled : row.status === 1
      }
      this.$nextTick(() => {
        this.$refs.couponForm && this.$refs.couponForm.clearValidate()
      })
      this.dialogVisible = true
    },
    handleTypeChange() {
      this.$nextTick(() => {
        this.$refs.couponForm && this.$refs.couponForm.clearValidate()
      })
    },
    handleDelete(row) {
      this.$confirm(`确定删除优惠券"${row.name}"吗？删除后不可恢复。`, '删除确认', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(() => {
        couponApi.delete(row.id).then(res => {
          if (res.code === 0) {
            this.$message.success('删除成功')
            this.fetchList()
          } else {
            this.$message.error(res.msg || '删除失败')
          }
        })
      }).catch(() => {})
    },
    handleStatusChange(row) {
      const newStatus = row.enabled ? 1 : 0
      couponApi.updateStatus(row.id, newStatus).then(res => {
        if (res.code === 0) {
          this.$message.success(row.enabled ? '已启用' : '已禁用')
        } else {
          row.enabled = !row.enabled
          this.$message.error(res.msg || '状态更新失败')
        }
      }).catch(() => {
        row.enabled = !row.enabled
      })
    },
    submitForm() {
      this.$refs.couponForm.validate(valid => {
        if (!valid) return

        if (!this.form.dateRange || this.form.dateRange.length !== 2) {
          this.$message.error('请选择有效期')
          return
        }

        this.submitLoading = true
        const data = {
          name: this.form.name,
          type: this.form.type,
          startTime: this.form.dateRange[0],
          endTime: this.form.dateRange[1],
          totalCount: this.form.totalCount,
          status: this.form.enabled ? 1 : 0
        }

        if (this.form.type === 'full_reduction') {
          data.minAmount = this.form.minAmount
          data.reduceAmount = this.form.reduceAmount
        } else {
          data.thresholdAmount = this.form.thresholdAmount
          data.discountRate = this.form.discountRate
        }

        let apiCall
        if (this.dialogMode === 'create') {
          apiCall = couponApi.create(data)
        } else {
          apiCall = couponApi.update(this.editingId, data)
        }

        apiCall.then(res => {
          if (res.code === 0) {
            this.$message.success(this.dialogMode === 'create' ? '添加成功' : '修改成功')
            this.dialogVisible = false
            this.fetchList()
          } else {
            this.$message.error(res.msg || '操作失败')
          }
        }).finally(() => {
          this.submitLoading = false
        })
      })
    },
    handleSizeChange(val) {
      this.pageSize = val
      this.fetchList()
    },
    handleCurrentChange(val) {
      this.page = val
      this.fetchList()
    }
  }
}
</script>

